22	const MAIN_ITEM_BASE: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	};
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const COMPONENT_BASE = 25;
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE = 60;
33	
34	const PROCESSING_FEE = 5;
35	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
36	const CURSED_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const LOYALTY_THRESHOLD_YEARS = 2;
40	const LOYALTY_DISCOUNT_RATE = 0.2;
41	const FOLLOWUP_DISCOUNT_RATE = 0.15;
42	
43	const componentGroupBase = (count: number): number => {
44	  if (count === BLOCK_SIZE) return BLOCK_BASE;
45	  return count * COMPONENT_BASE;
46	};
47	
48	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
49	
50	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
51	
52	const sumMainItems = (items: Item[]): number =>
53	  mainItems(items).reduce((total, item) => total + MAIN_ITEM_BASE[item.type], 0);
54	
55	const countByType = (items: Item[]): Record<string, number> => {
56	  const counts: Record<string, number> = {};
57	  for (const item of items) {
58	    counts[item.type] = (counts[item.type] ?? 0) + 1;
59	  }
60	  return counts;
61	};
62	
63	const sumComponentGroups = (items: Item[]): number => {
64	  const counts = countByType(items.filter(isComponent));
65	  return Object.values(counts).reduce((total, count) => total + componentGroupBase(count), 0);
66	};
67	
68	const policyBasePremium = (items: Item[]): number =>
69	  sumMainItems(items) + sumComponentGroups(items);
70	
71	const cursedSurcharge = (item: Item): number => {
72	  const base = MAIN_ITEM_BASE[item.type];
73	  return item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
74	};
75	
76	const highEnchantmentSurcharge = (item: Item): number => {
77	  const base = MAIN_ITEM_BASE[item.type];
78	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
79	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
80	    : 0;
81	};
82	
83	const itemSurcharges = (items: Item[]): number =>
84	  mainItems(items).reduce(
85	    (total, item) => total + cursedSurcharge(item) + highEnchantmentSurcharge(item),
86	    0,
87	  );
88	
89	const loyaltyDiscount = (base: number, customer: Customer): number =>
90	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
91	
92	const adjustedPremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
93	  const base = policyBasePremium(items);
94	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
95	  const followUpDiscount = isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
96	  return (
97	    base +
98	    firstInsuranceSurcharge -
99	    loyaltyDiscount(base, customer) -
100	    followUpDiscount +
101	    itemSurcharges(items)
102	  );
103	};
104	
105	const quotePremium = (step: QuoteStep, customer: Customer, isFollowUp: boolean): number =>
106	  Math.ceil(adjustedPremium(step.items, customer, isFollowUp)) + PROCESSING_FEE;
107	
108	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
109	  let quoteCount = 0;
110	  const results = scenario.steps.map((step) => {
111	    const isFollowUp = quoteCount > 0;
112	    quoteCount += 1;
113	    return { premium: quotePremium(step, scenario.customer, isFollowUp) };
114	  });
115	  return { results };
116	};
